                    i += 2  # Skip both quotes in one go
                else:
                    # End of quoted field
                    in_quotes = False
                    i += 1
            else:
                if len(current) == 0:
                    in_quotes = True
                    i += 1
                else:
                    current.append('"')
                    i += 1
        elif ch == ',' and not in_quotes:
            fields.append(''.join(current))
            current = []
            i += 1
        elif ch == '\n' and not in_quotes:
            break
        else:
            current.append(ch)
            i += 1
    fields.append(''.join(current))
    return fields

