    def unescape_json_pointer(token):
        """Unescape JSON Pointer token according to RFC 6901."""
        return token.replace('~1', '/').replace('~0', '~')

    def parse_json_pointer(path):
        """Parse JSON Pointer path into tokens."""
        if path == '':
            return []
        if not path.startswith('/'):
            raise ValueError("JSON Pointer must start with '/'")

        # Split by '/' and remove the first empty element
        tokens = path[1:].split('/')
        # Unescape each token
        return [unescape_json_pointer(token) for token in tokens]

    for patch in patches:
        op = patch['op']
        path = patch['path']
        value = patch.get('value')

        # Parse JSON pointer
        parts = parse_json_pointer(path)

        # Handle root document case (empty path)
        if len(parts) == 0:
            if op == 'replace':
                result = value
            elif op == 'remove':
                raise ValueError("Cannot remove root document")
            elif op == 'add':
