def topo_sort(edges):
    """Topological sort of a directed graph.
    edges: list of (from_node, to_node) tuples
    Returns a list of nodes in topological order.
    Raises ValueError if the graph contains a cycle.
    """
    if not edges:
        return []

    # Build adjacency list and collect all nodes
    graph = {}
    all_nodes = set()

    for src, dst in edges:
        all_nodes.add(src)
        all_nodes.add(dst)
        if src not in graph:
            graph[src] = set()  # Use set to deduplicate parallel edges
        if dst not in graph:
            graph[dst] = set()
        graph[src].add(dst)  # Set automatically handles duplicates

    # Calculate in-degrees based on unique edges only
    in_degree = {node: 0 for node in all_nodes}
    for node in graph:
        for neighbor in graph[node]:
            in_degree[neighbor] += 1

    # Kahn's algorithm
    queue = [node for node in all_nodes if in_degree[node] == 0]
    result = []

    while queue:
        node = queue.pop(0)
        result.append(node)
        for neighbor in graph[node]:
            in_degree[neighbor] -= 1
            if in_degree[neighbor] == 0:
                queue.append(neighbor)

    if len(result) != len(all_nodes):
        raise ValueError('Graph contains a cycle')

    return result

